int i386_cpuid_caches(size_t *data_caches) {
    int i;
    int num_data_caches = 0;
    for (i = 0; i < 32; i++) {


        uint32_t eax, ebx, ecx, edx;

        eax = 4; 
        ecx = i; 

        asm("cpuid"     
            : "+a"(eax) 
              ,
              "=b"(ebx), "+c"(ecx) 
              ,
              "=d"(edx)); 





        int cache_type = eax & 0x1F;

        if (cache_type == 0) 
            break;

        char *cache_type_string;
        switch (cache_type) {
        case 1:
            cache_type_string = "Data Cache";
            break;
        case 2:
            cache_type_string = "Instruction Cache";
            break;
        case 3:
            cache_type_string = "Unified Cache";
            break;
        default:
            cache_type_string = "Unknown Type Cache";
            break;
        }

        int cache_level = (eax >>= 5) & 0x7;

        int cache_is_self_initializing =
            (eax >>= 3) & 0x1; 
        int cache_is_fully_associative = (eax >>= 1) & 0x1;




        unsigned int cache_sets = ecx + 1;
        unsigned int cache_coherency_line_size = (ebx & 0xFFF) + 1;
        unsigned int cache_physical_line_partitions =
            ((ebx >>= 12) & 0x3FF) + 1;
        unsigned int cache_ways_of_associativity = ((ebx >>= 10) & 0x3FF) + 1;


        size_t cache_total_size = cache_ways_of_associativity *
                                  cache_physical_line_partitions *
                                  cache_coherency_line_size * cache_sets;

        if (cache_type == 1 || cache_type == 3) {
            data_caches[num_data_caches++] = cache_total_size;
        }

        printf("Cache ID %d:\n"
               "- Level: %d\n"
               "- Type: %s\n"
               "- Sets: %d\n"
               "- System Coherency Line Size: %d bytes\n"
               "- Physical Line partitions: %d\n"
               "- Ways of associativity: %d\n"
               "- Total Size: %zu bytes (%zu kb)\n"
               "- Is fully associative: %s\n"
               "- Is Self Initializing: %s\n"
               "\n",
               i, cache_level, cache_type_string, cache_sets,
               cache_coherency_line_size, cache_physical_line_partitions,
               cache_ways_of_associativity, cache_total_size,
               cache_total_size >> 10,
               cache_is_fully_associative ? "true" : "false",
               cache_is_self_initializing ? "true" : "false");
    }

    return num_data_caches;
}

int test_cache(size_t attempts, size_t lower_cache_size, int *latencies,
               size_t max_latency) {
    int fd = open("/dev/urandom", O_RDONLY);
    if (fd < 0) {
        perror("open");
        abort();
    }
    char *random_data = mmap(NULL, lower_cache_size, PROT_READ | PROT_WRITE,
                             MAP_PRIVATE | MAP_ANON 
                             ,
                             -1, 0); 
    if (random_data == MAP_FAILED) {
        perror("mmap");
        abort();
    }

    size_t i;
    for (i = 0; i < lower_cache_size; i += sysconf(_SC_PAGESIZE)) {
        random_data[i] = 1;
    }

    int64_t random_offset = 0;
    while (attempts--) {

        random_offset += rand();
        random_offset %= lower_cache_size;
        int32_t cycles_used, edx, temp1, temp2;
        asm("mfence\n\t" 
            "rdtsc\n\t"  
            "mov %%edx, %2\n\t"
            "mov %%eax, %3\n\t"
            "mfence\n\t"       
            "mov %4, %%al\n\t" 
            "mfence\n\t"
            "rdtsc\n\t"
            "sub %2, %%edx\n\t" 
            "sbb %3, %%eax"     
            : "=&a"(cycles_used), "=&d"(edx), "=&r"(temp1), "=&r"(temp2)
            : "m"(random_data[random_offset]));

        if (cycles_used < max_latency)
            latencies[cycles_used]++;
        else
            latencies[max_latency - 1]++;
    }

    munmap(random_data, lower_cache_size);

    return 0;
}

